mapper.update:
update dy_viewer_comment
set lead_id = #{leadId},
    viewer_id = #{viewerId},
    match_type = 'nickname'
where lead_id is null
  and lead_date = #{leadDate}
  and room_key = #{roomKey}
  and nickname = #{nickname}

mapper.select:
select
    latest.lead_id, latest.lead_date, latest.room_key, latest.douyin_user_id,
    coalesce(nullif(r.room_name, ''), nullif(latest.live_room_name, ''), latest.room_key) as live_room_name,
    v.viewer_id, v.sec_uid,
    coalesce(nullif(v.nickname, ''), latest.nickname) as nickname,
    ifnull(v.has_comment, 0) as has_comment,
    ifnull(v.comment_count, 0) as comment_count,
    v.first_comment_time, v.last_comment_time, v.last_comment_content,
    ifnull(v.status, 'new') as status,
    ifnull(v.intent, 'unknown') as intent,
    v.owner_id, v.owner_name, v.owner_assigned_time, v.order_no, v.remark,
    v.last_follow_time, null as next_follow_time, v.manual_update_time,
    v.first_seen_date, v.last_seen_date,
    visit.visit_count, visit.first_visit_date, visit.last_visit_date,
    latest.create_time, greatest(ifnull(v.update_time, latest.update_time), latest.update_time) as update_time
from (
    select l.*
    from dy_viewer_daily_lead l
    inner join (
        select viewer_id, max(lead_id) as lead_id
        from dy_viewer_daily_lead l
        left join dy_live_room r on r.room_key = l.room_key


                and l.lead_date = #{leadDate}


                and l.lead_date >= #{beginLeadDate}


                and l.lead_date <= #{endLeadDate}


                and l.room_key = #{roomKey}


                and coalesce(r.room_name, l.live_room_name, l.room_key) like concat('%', #{roomName}, '%')


                and l.nickname like concat('%', #{nickname}, '%')


        group by viewer_id
    ) picked on picked.lead_id = l.lead_id
) latest
inner join dy_viewer v on v.viewer_id = latest.viewer_id
left join dy_live_room r on r.room_key = latest.room_key
left join (
    select l.viewer_id, count(distinct l.lead_date) as visit_count, min(l.lead_date) as first_visit_date, max(l.lead_date) as last_visit_date
    from dy_viewer_daily_lead l
    left join dy_live_room r on r.room_key = l.room_key


            and l.lead_date = #{leadDate}


            and l.lead_date >= #{beginLeadDate}


            and l.lead_date <= #{endLeadDate}


            and l.room_key = #{roomKey}


            and coalesce(r.room_name, l.live_room_name, l.room_key) like concat('%', #{roomName}, '%')


    group by l.viewer_id
) visit on visit.viewer_id = latest.viewer_id


        and coalesce(v.nickname, latest.nickname) like concat('%', #{nickname}, '%')


        and ifnull(v.has_comment, 0) = #{hasComment}


        and ifnull(v.status, 'new') = #{status}


        and ifnull(v.status, 'new') not in ('ordered', 'pre_ordered')


        and ifnull(v.intent, 'unknown') = #{intent}


        and v.owner_id = #{ownerId}


        and v.owner_name like concat('%', #{ownerName}, '%')


        and v.order_no like concat('%', #{orderNo}, '%')


order by ifnull(v.has_comment, 0) desc, v.last_comment_time desc, latest.update_time desc

select room_name from ( select distinct coalesce(nullif(r.room_name, ''), nullif(l.live_room_name, ''), l.room_key) as room_name from dy_viewer_daily_lead l left join dy_live_room r on r.room_key = l.room_key where coalesce(nullif(r.room_name, ''), nullif(l.live_room_name, ''), l.room_key) is not null and coalesce(nullif(r.room_name, ''), nullif(l.live_room_name, ''), l.room_key) != ''
and coalesce(nullif(r.room_name, ''), nullif(l.live_room_name, ''), l.room_key) like concat('%', #{keyword}, '%')
) t order by room_name asc limit 20

mapper.update:
update dy_viewer_daily_lead
status = #{status}, intent = #{intent}, owner_id = #{ownerId}, owner_name = nullif(#{ownerName}, ''), owner_assigned_time = #{ownerAssignedTime}, order_no = #{orderNo}, remark = #{remark}, manual_update_time = sysdate(), update_time = sysdate()
where lead_id = #{leadId}

mapper.select:
select
    count(1) as totalCount,
    sum(case when ifnull(v.has_comment, 0) = 1 then 1 else 0 end) as commentLeadCount,
    sum(case when ifnull(v.status, 'new') = 'new' then 1 else 0 end) as newCount,
    sum(case when ifnull(v.status, 'new') = 'following' then 1 else 0 end) as followingCount,
    sum(case when ifnull(v.status, 'new') = 'pre_ordered' then 1 else 0 end) as preOrderedCount,
    sum(case when ifnull(v.status, 'new') = 'ordered' then 1 else 0 end) as orderedCount,
    max(latest.update_time) as lastUpdateTime
from (
    select l.viewer_id, max(l.update_time) as update_time
    from dy_viewer_daily_lead l
    left join dy_live_room r on r.room_key = l.room_key


            and l.lead_date = #{leadDate}


            and l.lead_date >= #{beginLeadDate}


            and l.lead_date <= #{endLeadDate}


            and l.room_key = #{roomKey}


            and coalesce(r.room_name, l.live_room_name, l.room_key) like concat('%', #{roomName}, '%')


            and l.nickname like concat('%', #{nickname}, '%')


    group by l.viewer_id
) latest
inner join dy_viewer v on v.viewer_id = latest.viewer_id


        and v.nickname like concat('%', #{nickname}, '%')


        and ifnull(v.has_comment, 0) = #{hasComment}


        and ifnull(v.status, 'new') = #{status}


        and ifnull(v.status, 'new') not in ('ordered', 'pre_ordered')


        and ifnull(v.intent, 'unknown') = #{intent}


        and v.owner_id = #{ownerId}


        and v.owner_name like concat('%', #{ownerName}, '%')

select hour(c.captured_at) as statHour, count(1) as commentCount, count(distinct c.viewer_id) as commentViewerCount from dy_viewer_comment c left join dy_viewer_daily_lead l on l.lead_id = c.lead_id left join dy_viewer v on v.viewer_id = c.viewer_id left join dy_live_room r on r.room_key = c.room_key
1 = 1 and c.lead_id is not null and c.viewer_id is not null
and c.lead_date = #{leadDate}
and c.lead_date >= #{beginLeadDate}
and c.lead_date <= #{endLeadDate}
and coalesce(nullif(r.room_name, ''), nullif(l.live_room_name, ''), c.room_key) like concat('%', #{roomName}, '%')
and v.owner_name like concat('%', #{ownerName}, '%')
group by hour(c.captured_at) order by statHour asc

with filtered_comment as ( select c.content from dy_viewer_comment c left join dy_viewer_daily_lead l on l.lead_id = c.lead_id left join dy_viewer v on v.viewer_id = c.viewer_id left join dy_live_room r on r.room_key = c.room_key
c.lead_id is not null and c.viewer_id is not null and c.content is not null and trim(c.content) != '' and c.lead_date = #{leadDate} and c.lead_date >= #{beginLeadDate} and c.lead_date <= #{endLeadDate} and coalesce(nullif(r.room_name, ''), nullif(l.live_room_name, ''), c.room_key) like concat('%', #{roomName}, '%') and v.owner_name like concat('%', #{ownerName}, '%')
), signal_dict as ( select '下单' as word, '购买信号' as category, 10 as weight union all select '订单', '购买信号', 9 union all select '怎么买', '购买信号', 9 union all select '链接', '购买信号', 8 union all select '拍哪个', '购买信号', 8 union all select '现在买', '购买信号', 9 union all select '多少钱', '价格敏感', 8 union all select '价格', '价格敏感', 7 union all select '优惠', '价格敏感', 7 union all select '便宜', '价格敏感', 5 union all select '区别', '型号对比', 7 union all select '对比', '型号对比', 6 union all select '型号', '型号对比', 5 union all select '哪个好', '型号对比', 7 union all select '适合', '型号对比', 5 union all select '赠品', '赠品活动', 6 union all select '活动', '赠品活动', 5 union all select '送什么', '赠品活动', 5 union all select '安装', '安装售后', 7 union all select '上门', '安装售后', 7 union all select '发货', '安装售后', 6 union all select '售后', '安装售后', 6 union all select '保修', '安装售后', 5 union all select '急用', '强需求', 9 union all select '马上', '强需求', 6 union all select '今天', '强需求', 5 union all select '孩子', '使用场景', 4 union all select '学习', '使用场景', 4 union all select '一年级', '使用场景', 6 union all select '二年级', '使用场景', 6 union all select '三年级', '使用场景', 6 ) select d.word, d.category, count(1) as hitCount, count(distinct f.content) as commentCount, count(1) * d.weight as score, d.weight from filtered_comment f inner join signal_dict d on f.content like concat('%', d.word, '%') group by d.word, d.category, d.weight order by score desc, hitCount desc limit 30

select 'empty_nickname' as issueType, count(1) as issueCount
from dy_viewer_daily_lead l
where (l.nickname is null or trim(l.nickname) = '')
and l.lead_date = #{leadDate}
and l.lead_date >= #{beginLeadDate}
and l.lead_date <= #{endLeadDate}
union all
select 'empty_room_name' as issueType, count(1) as issueCount
from dy_viewer_daily_lead l
left join dy_live_room r on r.room_key = l.room_key
where coalesce(nullif(r.room_name, ''), nullif(l.live_room_name, '')) is null
and l.lead_date = #{leadDate}
and l.lead_date >= #{beginLeadDate}
and l.lead_date <= #{endLeadDate}
union all
select 'unassigned_high_intent' as issueType, count(1) as issueCount
from dy_viewer_daily_lead l
inner join dy_viewer v on v.viewer_id = l.viewer_id
left join dy_live_room r on r.room_key = l.room_key
where ifnull(l.has_comment, 0) = 1
  and nullif(v.owner_name, '') is null
  and ifnull(v.status, 'new') not in ('ordered', 'pre_ordered', 'invalid')
and l.lead_date = #{leadDate}
and l.lead_date >= #{beginLeadDate}
and l.lead_date <= #{endLeadDate}
and coalesce(nullif(r.room_name, ''), nullif(l.live_room_name, ''), l.room_key) like concat('%', #{roomName}, '%')
and v.owner_name like concat('%', #{ownerName}, '%')
